<svg xmlns="http://www.w3.org/2000/svg" width="1920" height="1080"><defs><linearGradient id="b" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" style="stop-color:#0c0c1e"/><stop offset="100%" style="stop-color:#1a1a3e"/></linearGradient></defs><rect width="1920" height="1080" fill="url(#b)"/><circle cx="300" cy="200" r="150" fill="none" stroke="#FFD700" stroke-width="2" opacity="0.3"/><circle cx="1600" cy="800" r="200" fill="none" stroke="#FF4500" stroke-width="2" opacity="0.3"/><text x="960" y="200" text-anchor="middle" font-family="sans-serif" font-size="42" fill="#FFD700" opacity="0.8">第一集</text><text x="960" y="400" text-anchor="middle" font-family="sans-serif" font-size="110" font-weight="bold" fill="#FFD700">废物？</text><text x="960" y="540" text-anchor="middle" font-family="sans-serif" font-size="110" font-weight="bold" fill="#FF4500">你配吗！</text><text x="960" y="660" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#aaa">叶尘 · 灵根被夺三年 · 今日觉醒</text><rect x="0" y="950" width="1920" height="130" fill="rgba(255,215,0,0.1)"/><text x="960" y="1020" text-anchor="middle" font-family="sans-serif" font-size="32" fill="#FFD700">《万古第一神》· 玄幻逆袭</text></svg>
