cat > "$D/s03.svg" << 'SVG'
<svg xmlns="http://www.w3.org/2000/svg" width="1920" height="1080"><rect width="1920" height="1080" fill="#0a0a20"/><text x="960" y="120" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#00ff88">后山悬崖 · 深夜</text><ellipse cx="960" cy="600" rx="400" ry="250" fill="none" stroke="#00ff88" stroke-width="3" opacity="0.5"/><text x="960" y="550" text-anchor="middle" font-family="sans-serif" font-size="60" fill="#00ff88">混沌传承</text><text x="960" y="620" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#00ff88">觉醒中……</text><text x="960" y="780" text-anchor="middle" font-family="sans-serif" font-size="40" fill="#fff">一股远古洪荒之力涌入叶尘体内</text><text x="960" y="840" text-anchor="middle" font-family="sans-serif" font-size="32" fill="#aaa">他的左眼，缓缓亮起金色光芒</text><rect x="0" y="950" width="1920" height="130" fill="rgba(0,255,136,0.1)"/><text x="960" y="1020" text-anchor="middle" font-family="sans-serif" font-size="28" fill="#00ff88">沉睡万年的混沌神帝记忆开始苏醒</text></svg>
