cat > "$D/s04.svg" << 'SVG'
<svg xmlns="http://www.w3.org/2000/svg" width="1920" height="1080"><rect width="1920" height="1080" fill="#0c0c1e"/><text x="960" y="120" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#FFD700">三日后 · 叶家演武场</text><text x="960" y="350" text-anchor="middle" font-family="sans-serif" font-size="55" fill="#fff">龙傲天：废物，跪下叫爷爷！</text><rect x="400" y="430" width="1120" height="4" fill="#FFD700" opacity="0.5"/><text x="960" y="550" text-anchor="middle" font-family="sans-serif" font-size="70" font-weight="bold" fill="#FF4500">叶尘一拳轰出！</text><text x="960" y="650" text-anchor="middle" font-family="sans-serif" font-size="50" fill="#FFD700">"这一拳，替我自己打的。"</text><text x="960" y="780" text-anchor="middle" font-family="sans-serif" font-size="40" fill="#fff">龙傲天飞出十米，口吐鲜血</text><text x="960" y="840" text-anchor="middle" font-family="sans-serif" font-size="32" fill="#aaa">全场鸦雀无声</text><rect x="0" y="950" width="1920" height="130" fill="rgba(255,69,0,0.1)"/><text x="960" y="1020" text-anchor="middle" font-family="sans-serif" font-size="28" fill="#FF4500">废物逆袭，从今天开始！</text></svg>
