cat > "$D/s05.svg" << 'SVG'
<svg xmlns="http://www.w3.org/2000/svg" width="1920" height="1080"><rect width="1920" height="1080" fill="#0c0c1e"/><text x="960" y="150" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#FFD700">叶家众人</text><text x="960" y="320" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#fff">"这……这不可能！"</text><text x="960" y="400" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#fff">"他明明是个废物啊！"</text><text x="960" y="520" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#aaa">大长老脸色铁青：</text><text x="960" y="600" text-anchor="middle" font-family="sans-serif" font-size="50" fill="#FF4500">"他的实力……至少筑基境！"</text><text x="960" y="730" text-anchor="middle" font-family="sans-serif" font-size="40" fill="#FFD700">叶尘转身，金色瞳孔扫过全场：</text><text x="960" y="810" text-anchor="middle" font-family="sans-serif" font-size="50" fill="#fff">"还有谁，要叫我废物？"</text><rect x="0" y="950" width="1920" height="130" fill="rgba(255,215,0,0.1)"/><text x="960" y="1020" text-anchor="middle" font-family="sans-serif" font-size="28" fill="#FFD700">下集预告：叶尘踏入修真界</text></svg>
SVG

echo "=== Drama 1 玄幻逆袭: 5 slides done ==="

