<svg xmlns="http://www.w3.org/2000/svg" width="1920" height="1080"><defs><linearGradient id="b" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" style="stop-color:#1a0000"/><stop offset="100%" style="stop-color:#0a0a0a"/></linearGradient></defs><rect width="1920" height="1080" fill="url(#b)"/><text x="960" y="180" text-anchor="middle" font-family="sans-serif" font-size="42" fill="#ff4444" opacity="0.8">第一集</text><text x="960" y="380" text-anchor="middle" font-family="sans-serif" font-size="100" font-weight="bold" fill="#fff">五年戎马</text><text x="960" y="520" text-anchor="middle" font-family="sans-serif" font-size="100" font-weight="bold" fill="#ff4444">今日归来</text><text x="960" y="660" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#aaa">林北 · 北境之王 · 十万将士之主</text><rect x="0" y="950" width="1920" height="130" fill="rgba(255,0,0,0.1)"/><text x="960" y="1020" text-anchor="middle" font-family="sans-serif" font-size="32" fill="#ff4444">《战神归来》· 都市战神</text></svg>
