cat > "$D/s02.svg" << 'SVG'
<svg xmlns="http://www.w3.org/2000/svg" width="1920" height="1080"><rect width="1920" height="1080" fill="#0a0a0a"/><text x="960" y="120" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#ff4444">江城机场</text><text x="960" y="300" text-anchor="middle" font-family="sans-serif" font-size="50" fill="#fff">一个穿着旧军装的男人走出机场</text><text x="960" y="380" text-anchor="middle" font-family="sans-serif" font-size="40" fill="#aaa">没有欢迎仪式，没有接机的人</text><text x="960" y="500" text-anchor="middle" font-family="sans-serif" font-size="55" fill="#ff4444">他叫林北</text><text x="960" y="580" text-anchor="middle" font-family="sans-serif" font-size="40" fill="#aaa">五年前被家族赶出，入伍参军</text><text x="960" y="660" text-anchor="middle" font-family="sans-serif" font-size="40" fill="#aaa">五年后，他是北境战神</text><text x="960" y="780" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#fff">但此刻，他只想回家看看母亲</text><rect x="0" y="950" width="1920" height="130" fill="rgba(255,0,0,0.1)"/><text x="960" y="1020" text-anchor="middle" font-family="sans-serif" font-size="28" fill="#666">没人知道，这个"穷当兵的"有多恐怖</text></svg>
