cat > "$D/s04.svg" << 'SVG'
<svg xmlns="http://www.w3.org/2000/svg" width="1920" height="1080"><rect width="1920" height="1080" fill="#0a0a0a"/><text x="960" y="120" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#ff4444">十分钟后</text><text x="960" y="280" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#fff">三辆军用吉普停在门口</text><text x="960" y="360" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#fff">十二名荷枪实弹的士兵列队</text><text x="960" y="480" text-anchor="middle" font-family="sans-serif" font-size="60" font-weight="bold" fill="#ff4444">"敬礼！"</text><text x="960" y="600" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#fff">林家家主颤抖着跑出来</text><text x="960" y="680" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#fff">"扑通"一声跪在地上</text><text x="960" y="800" text-anchor="middle" font-family="sans-serif" font-size="50" fill="#FFD700">"北……北境之王……"</text><rect x="0" y="950" width="1920" height="130" fill="rgba(255,0,0,0.1)"/><text x="960" y="1020" text-anchor="middle" font-family="sans-serif" font-size="28" fill="#ff4444">曾经被赶出家门的废物，如今万人之上</text></svg>
