cat > "$D/s02.svg" << 'SVG'
<svg xmlns="http://www.w3.org/2000/svg" width="1920" height="1080"><rect width="1920" height="1080" fill="#001a33"/><text x="960" y="120" text-anchor="middle" font-family="sans-serif" font-size="36" fill="#00bfff">2010年·高三教室</text><text x="960" y="300" text-anchor="middle" font-family="sans-serif" font-size="50" fill="#fff">陈默猛然惊醒</text><text x="960" y="400" text-anchor="middle" font-family="sans-serif" font-size="50" fill="#fff">黑板上写着：高考倒计时180天</text><text x="960" y="520" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#aaa">他记得一切</text><text x="960" y="590" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#aaa">前世被女友背叛、被兄弟出卖</text><text x="960" y="660" text-anchor="middle" font-family="sans-serif" font-size="45" fill="#aaa">母亲病死在出租屋，他连医药费都凑不齐</text><text x="960" y="780" text-anchor="middle" font-family="sans-serif" font-size="55" fill="#00bfff">他低头看了看自己的手</text><text x="960" y="860" text-anchor="middle" font-family="sans-serif" font-size="50" fill="#fff">"这一次，我不会再错过任何东西。"</text><rect x="0" y="950" width="1920" height="130" fill="rgba(0,191,255,0.1)"/><text x="960" y="1020" text-anchor="middle" font-family="sans-serif" font-size="28" fill="#00bfff">左手无名指上，一枚古朴戒指隐隐发光</text></svg>
